using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class TrainingMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _modelPath;
    private readonly string _dataPath;
    private TrainingMetricsResponse? _lastMetrics;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public TrainingMetricsResponse? LastMetrics => _lastMetrics;

    public TrainingMetricsResponse TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.NormalizeMinMax("PriorityNorm", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", "PriorityNorm"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model on {Rows} rows...", split.TrainSet.GetRowCount());

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation(
            "Evaluation — MacroAccuracy: {MacroAcc:F4}, MicroAccuracy: {MicroAcc:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        // Train the final model on all data for production use
        var finalModel = pipeline.Fit(data);
        _mlContext.Model.Save(finalModel, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        _lastMetrics = BuildMetricsResponse(metrics);
        return _lastMetrics;
    }

    private static TrainingMetricsResponse BuildMetricsResponse(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        var response = new TrainingMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
        };

        foreach (var m in metrics.PerClassLogLoss.Select((logLoss, i) => new { Index = i, LogLoss = logLoss }))
        {
            response.PerCategoryMetrics.Add(new CategoryMetric
            {
                Category = $"Class_{m.Index}",
                Precision = double.NaN,
                Recall = double.NaN,
                F1Score = double.NaN,
            });
        }

        if (metrics.ConfusionMatrix.PerClassPrecision.Count > 0)
        {
            for (int i = 0; i < metrics.ConfusionMatrix.PerClassPrecision.Count; i++)
            {
                if (i < response.PerCategoryMetrics.Count)
                {
                    response.PerCategoryMetrics[i].Precision = metrics.ConfusionMatrix.PerClassPrecision[i];
                    response.PerCategoryMetrics[i].Recall = metrics.ConfusionMatrix.PerClassRecall[i];
                    var p = metrics.ConfusionMatrix.PerClassPrecision[i];
                    var r = metrics.ConfusionMatrix.PerClassRecall[i];
                    response.PerCategoryMetrics[i].F1Score = (p + r) > 0 ? 2 * p * r / (p + r) : 0;
                }
            }
        }

        return response;
    }

    public void EnsureModelExists()
    {
        if (!File.Exists(_modelPath))
        {
            _logger.LogInformation("No pre-trained model found. Training now...");
            TrainAndEvaluate();
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
        {
            confidence[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    [HttpPost("train")]
    public ActionResult<TrainingMetricsResponse> Train()
    {
        var metrics = _trainingService.TrainAndEvaluate();
        return Ok(metrics);
    }

    [HttpGet("metrics")]
    public ActionResult<TrainingMetricsResponse> GetMetrics()
    {
        var metrics = _trainingService.LastMetrics;
        if (metrics is null)
            return NotFound("No training metrics available. POST to /api/tickets/train first.");

        return Ok(metrics);
    }
}

