using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _modelPath;
    private readonly string _dataPath;
    private TrainingMetricsResponse? _lastMetrics;
    private string[] _categoryNames = [];

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public TrainingMetricsResponse? LastMetrics => _lastMetrics;
    public string[] CategoryNames => _categoryNames;

    public TrainingMetricsResponse TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.NormalizeMinMax("PriorityNorm", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", "PriorityNorm"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var trainCount = split.TrainSet.Preview().RowView.Length;
        _logger.LogInformation("Training model on {Rows} rows...", trainCount);

        var model = pipeline.Fit(split.TrainSet);

        // Extract category slot names from the trained model
        var labelCol = split.TrainSet.Schema["Category"];
        var trainPreview = model.Transform(split.TrainSet);
        ExtractCategoryNames(trainPreview);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation(
            "Evaluation — MacroAccuracy: {MacroAcc:F4}, MicroAccuracy: {MicroAcc:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        // Train the final model on all data for production use
        var finalModel = pipeline.Fit(data);
        _mlContext.Model.Save(finalModel, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        _lastMetrics = BuildMetricsResponse(metrics);
        return _lastMetrics;
    }

    private void ExtractCategoryNames(IDataView transformedData)
    {
        var scoreCol = transformedData.Schema["Score"];
        var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
        scoreCol.GetSlotNames(ref slotNames);
        _categoryNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        _logger.LogInformation("Model categories: {Categories}", string.Join(", ", _categoryNames));
    }

    private TrainingMetricsResponse BuildMetricsResponse(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        var response = new TrainingMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
        };

        var precision = metrics.ConfusionMatrix.PerClassPrecision;
        var recall = metrics.ConfusionMatrix.PerClassRecall;

        for (int i = 0; i < precision.Count; i++)
        {
            var p = precision[i];
            var r = recall[i];
            response.PerCategoryMetrics.Add(new CategoryMetric
            {
                Category = i < _categoryNames.Length ? _categoryNames[i] : $"Class_{i}",
                Precision = p,
                Recall = r,
                F1Score = (p + r) > 0 ? 2 * p * r / (p + r) : 0,
            });
        }

        return response;
    }

    public void EnsureModelExists()
    {
        if (!File.Exists(_modelPath))
        {
            _logger.LogInformation("No pre-trained model found. Training now...");
            TrainAndEvaluate();
        }
    }
}

