        {
            for (int i = 0; i < metrics.ConfusionMatrix.PerClassPrecision.Count; i++)
            {
                if (i < response.PerCategoryMetrics.Count)
                {
                    response.PerCategoryMetrics[i].Precision = metrics.ConfusionMatrix.PerClassPrecision[i];
                    response.PerCategoryMetrics[i].Recall = metrics.ConfusionMatrix.PerClassRecall[i];
                    var p = metrics.ConfusionMatrix.PerClassPrecision[i];
                    var r = metrics.ConfusionMatrix.PerClassRecall[i];
                    response.PerCategoryMetrics[i].F1Score = (p + r) > 0 ? 2 * p * r / (p + r) : 0;
                }
            }
        }

        return response;
    }

    public void EnsureModelExists()
    {
        if (!File.Exists(_modelPath))
        {
            _logger.LogInformation("No pre-trained model found. Training now...");
            TrainAndEvaluate();
        }
    }
