private void ExtractCategoryNames(IDataView transformedData)
{
    var scoreCol = transformedData.Schema["Score"];
    var slotNames = default(Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>);
    scoreCol.Annotations.GetValue("SlotNames", ref slotNames);
    _categoryNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    _logger.LogInformation("Model categories: {Categories}", string.Join(", ", _categoryNames));
}

